 51	const getRow: GetRow = ({
 52	  managedSystemKind,
 53	  systemName,
 54	  systemNamespace,
 55	  iopsData,
 56	  throughputData,
 57	  latencyData,
 58	  width,
 59	}) => {
 60	  const { apiGroup, apiVersion, kind } = getGVK(managedSystemKind);
 61	  const refKind = referenceFor(apiGroup)(apiVersion)(kind);
 62	  return [
 63	    <ResourceLink
 64	      key={systemName}
 65	      link={getDashboardLink(refKind, systemName, systemNamespace)}
