 86	      {...throughputData}
 87	      width={width}
 88	      divideBy={3}
 89	    />,
 90	  ];
 91	};
 92	
 93	const nameSort = (a: RowProps, b: RowProps, c: SortByDirection) => {
 94	  const negation = c !== SortByDirection.asc;
 95	  const sortVal = a.systemName.localeCompare(b.systemName);
 96	  return negation ? -sortVal : sortVal;
 97	};
 98	
 99	const metricsSort =
100	  (metric: 'iopsData' | 'throughputData' | 'latencyData') =>
101	  (a: RowProps, b: RowProps, c: SortByDirection) => {
102	    const negation = c !== SortByDirection.asc;
103	    const dataA = a[metric]?.data;
