157	  const [iops, iopsError, iopsLoading] = useCustomPrometheusPoll({
158	    query: UTILIZATION_QUERY[StorageDashboard.IOPS],
159	    endpoint: 'api/v1/query_range' as any,
160	    timespan: duration,
161	    basePath: usePrometheusBasePath(),
162	  });
163	
164	  const rawRows = generateDataFrames(systems, latency, throughput, iops, width);
165	
166	  const loading =
167	    !systemLoaded || latencyLoading || throughputLoading || iopsLoading;
168	  const error =
169	    !!systemLoadError || !!throughputError || !!latencyError || !!iopsError;
170	
171	  return (
172	    <Card>
173	      <div ref={ref}>
174	        <CardHeader>
175	          <Flex
176	            justifyContent={{ default: 'justifyContentSpaceBetween' }}
177	            className="odf-performanceCard__header--width"
178	          >
179	            <FlexItem>
180	              <CardTitle>{t('Performance')}</CardTitle>
181	            </FlexItem>
182	            <FlexItem>
183	              <UtilizationDurationDropdown />
184	            </FlexItem>
185	          </Flex>
