 47	type GetRow = (
 48	  args: RowProps
 49	) => [React.ReactNode, React.ReactNode, React.ReactNode, React.ReactNode];
 50	
 51	const getRow: GetRow = ({
 52	  managedSystemKind,
 53	  systemName,
 54	  systemNamespace,
 55	  iopsData,
 56	  throughputData,
 57	  latencyData,
 58	  width,
 59	}) => {
 60	  const { apiGroup, apiVersion, kind } = getGVK(managedSystemKind);
 61	  const refKind = referenceFor(apiGroup)(apiVersion)(kind);
 62	  return [
 63	    <ResourceLink
 64	      key={systemName}
 65	      link={getDashboardLink(refKind, systemName, systemNamespace)}
 66	      resourceModel={ODFStorageSystem}
 67	      resourceName={systemName}
 68	    />,
 69	
 70	    <LineGraph
 71	      key={`${systemName}_IOPS`}
 72	      {...iopsData}
 73	      width={width}
 74	      divideBy={3}
 75	    />,
 76	
 77	    <LineGraph
 78	      key={`${systemName}_LAT`}
 79	      {...latencyData}
 80	      width={width}
 81	      divideBy={3}
 82	    />,
 83	
 84	    <LineGraph
 85	      key={`${systemName}_THR`}
 86	      {...throughputData}
 87	      width={width}
 88	      divideBy={3}
 89	    />,
 90	  ];
 91	};
 92	
 93	const nameSort = (a: RowProps, b: RowProps, c: SortByDirection) => {
 94	  const negation = c !== SortByDirection.asc;
